import re
PFX="SENTINEL__"
tok=re.compile(re.escape(PFX)+r"([A-Za-z0-9_.]+)")

def per_line(rendered):
    # candidate (a): per-line reset
    out=[]
    for line in rendered.splitlines():
        depth=0; inside=[]
        for ch in line:
            if ch=='(': depth+=1; inside.append(True)
            elif ch==')': inside.append(depth>0); depth=max(0,depth-1)
            else: inside.append(depth>0)
        for m in tok.finditer(line):
            if m.start()<len(inside) and inside[m.start()]: continue
            out.append((line))
    return out

def balanced_match(rendered):
    # candidate (b): only positions inside a CLOSED (...) pair count as context.
    # Compute over whole text; an unmatched '(' contributes NO context region.
    text=rendered
    inside=[False]*len(text)
    stack=[]
    for i,ch in enumerate(text):
        if ch=='(': stack.append(i)
        elif ch==')':
            if stack:
                o=stack.pop()
                for j in range(o,i+1): inside[j]=True
    out=[]
    for m in tok.finditer(text):
        if inside[m.start()]: continue
        out.append(m.group(0))
    return out

